	<div id="app">
		<link rel="stylesheet" href="https://syui.ai/bower_components/icomoon/css/icomoon.css" />
		<div class="menu">
				<a href="/"><span class="icon-ai"></span></a> | <a href="/docs">docs</a>
			</div>
			<p><code><a href="https://bsky.app/profile/yui.bsky.social">@yui.bsky.social</a> /card</code></p>

		<div v-if="loc.length > 1">
			<div v-if="cards" class="bluesky-card">
				<h3>@{{ loc }}</h3>
				<span v-for="ii in cards.data">
					<span v-if="ii.status == 'normal'">
						<img :src='"/card/card_" + ii.card + ".webp"'>{{ ii.cp }}
					</span>
					<span v-if="ii.status == 'super'">
						<img :src='"/card/card_" + ii.card + ".gif"'>{{ ii.cp }}
					</span>
				</span>
			</div>
		</div>

		<div v-if="loc.length == 0">

			<form @submit.prevent="page">
				<input v-model="userid" placeholder="user" value="userid">
				<input type="submit">
			</form> 

			<div v-if="ucard" class="bluesky-card">
				<span v-for="u in ucard.data">
					<span v-if="u.status == 'normal'">
						<img :src='"/card/card_" + u.card + ".webp"'>{{ u.cp }}
					</span>
					<span v-if="u.status == 'super'">
						<img :src='"/card/card_" + u.card + ".gif"'>{{ u.cp }}
					</span>
				</span>
			</div>

			<form @submit.prevent="submit">
				<input v-model="id" placeholder="id" value="id">
				<input type="submit">
			</form> 

			<div v-if="cards" class="bluesky-card">
				<h3>{{ user.data.username }} card list</h3>
				<span v-for="ii in cards.data">
					<span v-if="ii.status == 'normal'">
						<img :src='"/card/card_" + ii.card + ".webp"'>{{ ii.cp }}
					</span>
					<span v-if="ii.status == 'super'">
						<img :src='"/card/card_" + ii.card + ".gif"'>{{ ii.cp }}
					</span>
				</span>
			</div>

			<div v-if="record" class="bluesky-record">
				<li v-for="i in record.data">
					<p><span class="text">id : {{ i.id }}</span></p>
					<p><span class="text"><a :href="'/' + i.username">{{ i.username }}</a></span></p>
				</li>
			</div>
		</div>

		<div v-if="loc === 'docs'">
			<p>カードは1日に1回、引くことができます</p>
			<p>カードの排出率は以下のとおりです</p>

			<table>
				<thead>
					<tr>
						<th>status</th>
					</tr>
				</thead>
				<tbody>
					<tr>
						<td>normal</td>
						<td>rare</td>
						<td>super</td>
					</tr>
					<tr>
						<td>90%</td>
						<td>10%</td>
						<td>1%</td>
					</tr>
				</tbody>
			</table>

			<p>カードには強さを表す数字が入っています</p>

			<table>
				<thead>
					<tr>
						<th>cp</th>
					</tr>
				</thead>
				<tbody>
					<tr>
						<td>normal</td>
						<td>rare</td>
						<td>super</td>
					</tr>
					<tr>
						<td>+0~250(1%)</td>
						<td>+0~250(100%)</td>
						<td>+0~500(100%)</td>
					</tr>
				</tbody>
				</table>

				<p>同じ<a href="https://syui.ai/photo">レアカード</a>を3枚集めると、いいことがあるかも</p>
				<p>匿名で受け取りたい郵便局を決めて <a href="https://bsky.app/profile/syui.bsky.social">@syui</a> まで連絡してみて</p>

		</div>

		<footer>
			© syui
		</footer>
	</div>
</template>

<script>
import axios from 'axios'
var loc = window.location.pathname.split('/').slice(-1)[0];

export default {
	name: "App",
	metaInfo: {
		title: "syui.ai",
	},
	data () {
		return {
			card: null,
			cards: null,
			loc: window.location.pathname.split('/').slice(-1)[0],
			id: null,
			record: null,
			url: null,
			user: null,
			userid: null,
			ucard: null,
			status: null,
		}
	},
	mounted() {
		axios.get("https://cors-card.herokuapp.com/https://api.syui.ai/users?itemsPerPage=255",{ crossdomain: true })
			.then(response => { 
			this.record = response;
			this.id = this.record.data.find((v) => v.username == loc).id;
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			if (loc.length > 1){
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.cards = response));
			}
		})
		.catch(error => console.log(error));
	},
	methods: {
		submit() {
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			axios
				.get(url,{ crossdomain: true })
				.then(response => (this.cards = response));
				axios
					.get("https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id,{ crossdomain: true })
					.then(response => (this.user = response));
		},
		page() {
			this.id = this.record.data.find((v) => v.username == this.userid).id;
			let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=255";
			axios
				.get(url,{ crossdomain: true })
				.then(response => (this.ucard = response));
				//window.location.href = '/' + this.user;
		}
	}
}
</script>

